{
    "type": "object",
    "properties": {
        "model_name": {
            "type": "string",
            "description": "Odoo technical model name, e.g. res.partner, sale.order, crm.lead, project.task, hr.employee"
        }
    },
    "required": ["model_name"]
}

if model_name not in env:
    ai['result'] = f"ERROR: Model '{model_name}' does not exist in Odoo."
else:
    fields = env[model_name].sudo().fields_get(
        attributes=['string', 'type', 'required', 'selection', 'relation', 'help']
    )

    SKIP_FIELDS = {
        'id', 'create_uid', 'create_date', 'write_uid', 'write_date',
        'message_ids', 'message_follower_ids', 'activity_ids',
        '__last_update', 'display_name', 'access_token',
    }
    SKIP_TYPES = {'one2many', 'binary', 'reference'}

    required_lines = []
    optional_lines = []

    for fname, fdef in fields.items():
        if fname in SKIP_FIELDS:
            continue
        if fdef['type'] in SKIP_TYPES:
            continue

        line = f"  {fname} | {fdef['string']} | {fdef['type']}"
        if fdef['type'] == 'many2one':
            line += f" -> {fdef.get('relation', '')} | use name_fields"
        if fdef['type'] == 'selection':
            opts = [str(v) for v, _ in (fdef.get('selection') or [])]
            line += f" | options: [{', '.join(opts)}]"

        if fdef.get('required'):
            required_lines.append(line)
        elif len(optional_lines) < 20:
            optional_lines.append(line)

    output = f"Model: {model_name}\nFormat: field_name | label | type | notes\n"
    output += "\nREQUIRED FIELDS (must provide):\n"
    output += "\n".join(required_lines) if required_lines else "  (none)"
    output += "\n\nCOMMON OPTIONAL FIELDS:\n"
    output += "\n".join(optional_lines) if optional_lines else "  (none)"

    ai['result'] = output

{
    "type": "object",
    "properties": {
        "model_name": {
            "type": "string",
            "description": "Odoo technical model name, e.g. res.partner, crm.lead, project.task"
        },
        "field_names": {
            "type": "array",
            "description": "List of Odoo technical field names to set. Must match field_values by index. E.g. ['name', 'email', 'phone', 'is_company']",
            "items": {"type": "string"}
        },
        "field_values": {
            "type": "array",
            "description": "List of values corresponding to field_names. Same order and length. All as strings: booleans as 'true'/'false', numbers as '1'/'0'. E.g. ['John', 'john@test.com', '123456', 'false']",
            "items": {"type": "string"}
        },
        "many2one_field_names": {
            "type": "array",
            "description": "List of Many2one field names where you only have a display name (system will resolve to ID). E.g. ['country_id', 'user_id']",
            "items": {"type": "string"}
        },
        "many2one_search_names": {
            "type": "array",
            "description": "List of display names to search for, matching many2one_field_names by index. E.g. ['Hong Kong', 'Administrator']",
            "items": {"type": "string"}
        }
    },
    "required": ["model_name", "field_names", "field_values", "many2one_field_names", "many2one_search_names"]
}

if model_name not in env:
    ai['result'] = f"ERROR: Model '{model_name}' does not exist."
else:
    all_fields = env[model_name].sudo().fields_get(
        attributes=['string', 'type', 'required', 'relation']
    )

    # ── Zip field_names + field_values into dict, auto-cast type ──
    vals = {}
    bad_fields = []
    for fname, fval in zip(field_names or [], field_values or []):
        if fname not in all_fields:
            bad_fields.append(fname)
            continue
        ftype = all_fields[fname]['type']
        if ftype == 'boolean':
            vals[fname] = fval.lower() in ('true', '1', 'yes')
        elif ftype == 'integer':
            vals[fname] = int(fval) if fval.lstrip('-').isdigit() else fval
        elif ftype in ('float', 'monetary'):
            vals[fname] = float(fval)
        else:
            vals[fname] = fval

    if bad_fields:
        ai['result'] = (
            f"ERROR: Unknown fields for {model_name}: {bad_fields}\n"
            f"Call 'AI: Get Model Fields' first to see valid field names."
        )
    else:
        # ── Check required fields ──
        SYSTEM_FIELDS = {'id', 'create_uid', 'write_uid', 'create_date', 'write_date', 'active'}
        m2o_keys = list(many2one_field_names or [])
        missing = [
            f"{f} ({all_fields[f]['string']}, {all_fields[f]['type']})"
            for f, d in all_fields.items()
            if d.get('required')
            and f not in SYSTEM_FIELDS
            and f not in vals
            and f not in m2o_keys
        ]
        if missing:
            ai['result'] = (
                f"ERROR: Missing required fields for {model_name}:\n"
                + "\n".join(f"  - {m}" for m in missing)
                + "\nPlease provide these fields and try again."
            )
        else:
            # ── Resolve many2one names to IDs ──
            resolve_error = None
            for fname, search_name in zip(many2one_field_names or [], many2one_search_names or []):
                if not fname or not search_name:
                    continue
                if fname not in all_fields:
                    resolve_error = f"ERROR: Field '{fname}' not found in {model_name}."
                    break
                related_model = all_fields[fname].get('relation')
                if not related_model:
                    resolve_error = f"ERROR: '{fname}' is not a Many2one field."
                    break
                found = env[related_model].sudo().search(
                    [['name', 'ilike', search_name]], limit=1
                )
                if not found:
                    resolve_error = f"ERROR: Cannot find '{search_name}' in {related_model}."
                    break
                vals[fname] = found.id

            if resolve_error:
                ai['result'] = resolve_error
            else:
                record = env[model_name].sudo().create(vals)
                ai['result'] = (
                    f"Created {model_name} record successfully.\n"
                    f"  ID: {record.id}\n"
                    f"  Name: {record.display_name}"
                )

{
    "type": "object",
    "properties": {
        "model_name": {
            "type": "string",
            "description": "Odoo technical model name, e.g. res.partner, crm.lead, project.task"
        },
        "record_id": {
            "type": "number",
            "description": "Database ID of the record to update. Use 0 if searching by name instead."
        },
        "search_name": {
            "type": "string",
            "description": "Name to search for the record if record_id is 0. Leave empty string if using record_id."
        },
        "field_names": {
            "type": "array",
            "description": "List of Odoo technical field names to update. Must match field_values by index.",
            "items": {"type": "string"}
        },
        "field_values": {
            "type": "array",
            "description": "List of new values corresponding to field_names. Same order and length. All as strings.",
            "items": {"type": "string"}
        }
    },
    "required": ["model_name", "record_id", "search_name", "field_names", "field_values"]
}

if model_name not in env:
    ai['result'] = f"ERROR: Model '{model_name}' does not exist."
elif not field_names:
    ai['result'] = "ERROR: No field_names provided to update."
else:
    all_fields = env[model_name].sudo().fields_get(
        attributes=['string', 'type']
    )

    # ── Zip field_names + field_values into dict, auto-cast type ──
    vals = {}
    bad_fields = []
    for fname, fval in zip(field_names, field_values or []):
        if fname not in all_fields:
            bad_fields.append(fname)
            continue
        ftype = all_fields[fname]['type']
        if ftype == 'boolean':
            vals[fname] = fval.lower() in ('true', '1', 'yes')
        elif ftype == 'integer':
            vals[fname] = int(fval) if fval.lstrip('-').isdigit() else fval
        elif ftype in ('float', 'monetary'):
            vals[fname] = float(fval)
        else:
            vals[fname] = fval

    if bad_fields:
        ai['result'] = (
            f"ERROR: Unknown fields: {bad_fields}\n"
            f"Call 'AI: Get Model Fields' to see valid field names."
        )
    else:
        target = None
        if record_id:
            target = env[model_name].sudo().browse(int(record_id))
            if not target.exists():
                ai['result'] = f"ERROR: No record with ID {record_id} in {model_name}."
                target = None
        elif search_name:
            target = env[model_name].sudo().search(
                [['name', 'ilike', search_name]], limit=1
            )
            if not target:
                ai['result'] = f"ERROR: Cannot find '{search_name}' in {model_name}."
                target = None
        else:
            ai['result'] = "ERROR: Provide either record_id or search_name."

        if target:
            target.write(vals)
            ai['result'] = (
                f"Updated {model_name} record successfully.\n"
                f"  ID: {target.id}\n"
                f"  Name: {target.display_name}\n"
                f"  Updated fields: {field_names}"
            )

{
    "type": "object",
    "properties": {
        "model_name": {
            "type": "string",
            "description": "Odoo technical model name, e.g. res.partner, crm.lead, project.task, hr.employee"
        },
        "record_id": {
            "type": "number",
            "description": "Database ID of the record to archive. Use 0 if searching by name instead."
        },
        "search_name": {
            "type": "string",
            "description": "Name to search for the record if record_id is 0. Leave empty string if using record_id."
        }
    },
    "required": ["model_name", "record_id", "search_name"]
}

if model_name not in env:
    ai['result'] = f"ERROR: Model '{model_name}' does not exist."
else:
    target = None

    if record_id:
        target = env[model_name].sudo().browse(int(record_id))
        if not target.exists():
            ai['result'] = f"ERROR: No record found with ID {record_id} in {model_name}."
            target = None
    elif search_name:
        target = env[model_name].sudo().search(
            [['name', 'ilike', search_name], ['active', '=', True]], limit=1
        )
        if not target:
            ai['result'] = f"ERROR: Cannot find active record '{search_name}' in {model_name}."
            target = None
    else:
        ai['result'] = "ERROR: Please provide either record_id or search_name."

    if target:
        record_name = target.display_name
        if 'active' not in env[model_name].sudo().fields_get(['active']):
            ai['result'] = f"ERROR: Model {model_name} does not support archiving (no active field)."
        else:
            target.write({'active': False})
            ai['result'] = (
                f"Archived {model_name} record successfully.\n"
                f"  ID: {target.id}\n"
                f"  Name: {record_name}"
            )
